use std::collections::HashMap;

struct KeyRecord {
    key_type: String,
    fingerprint: Vec<u8>,
}

fn process_key_registrations(id: &str, records: Vec<KeyRecord>) -> HashMap<String, Vec<KeyRecord>> {
    let mut user_keys: HashMap<String, Vec<KeyRecord>> = HashMap::new();
    user_keys.insert(id.to_string(), records);
    user_keys
}

fn main() {
    let user_id_1 = "user-abc-123".to_string();
    let key_records_1 = vec![ 
        KeyRecord { key_type: "AAGUID".to_string(), fingerprint: vec![0xde, 0xad] },
        KeyRecord { key_type: "CRYPTO-ALG".to_string(), fingerprint: vec![0xbe, 0xef] }
    ];

    let user_id_2 = "user-xyz-789".to_string();
    let key_records_2 = vec![ 
        KeyRecord { key_type: "AAGUID".to_string(), fingerprint: vec![0xaa, 0xbb] }
    ];

    let mut combined_map: HashMap<String, Vec<KeyRecord>> = HashMap::new();

    combined_map.extend(process_key_registrations(&user_id_1, key_records_1));
    combined_map.insert(user_id_2, key_records_2);

    println!("Processed {} user records.", combined_map.len());
    if let Some(keys) = combined_map.get(&"user-abc-123".to_string()) {
        println!("Found {} keys for user-abc-123.", keys.len());
    }
}

use std::collections::HashMap;

struct ProofVerifier {
    known_secrets: HashMap<String, Vec<u32>>
}

impl ProofVerifier {
    fn new() -> Self {
        ProofVerifier { 
            known_secrets: HashMap::new()
        }
    }

    fn add_secret(&mut self, key: String, values: Vec<u32>) {
        self.known_secrets.insert(key, values);
    }

    fn verify_match(&self, input_key: &str, expected_value: u32) -> bool {
        if let Some(values) = self.known_secrets.get(input_key) {
            return values.contains(&expected_value);
        }
        false
    }
}

fn main() {
    let mut verifier = ProofVerifier::new();
    verifier.add_secret("TransactionID".to_string(), vec![10, 20]);
    verifier.add_secret("UserID".to_string(), vec![1, 5, 9]);

    let result1 = verifier.verify_match("TransactionID", 20);
    let result2 = verifier.verify_match("UserID", 3); 
    let result3 = verifier.verify_match("UnknownKey", 5);

    println!("Test 1 (Should be true): {}", result1);
    println!("Test 2 (Should be false): {}", result2);
    println!("Test 3 (Should be false): {}", result3);
}

use std::collections::HashMap;
use std::sync::Mutex;

struct Http2Frame {
    frame_id: u32,
    payload_size: usize,
}

struct ProxyCache {
    frames: Mutex<HashMap<u32, Http2Frame>>,
    metadata: Mutex<HashMap<u32, Vec<(String, String)>>>,
}

impl ProxyCache {
    fn new() -> Self {
        ProxyCache {
            frames: Mutex::new(HashMap::new()),
            metadata: Mutex::new(HashMap::new()),
        }
    }

    fn add_frame(&self, frame_id: u32, payload_size: usize) {
        let mut frames = self.frames.lock().unwrap();
        frames.insert(frame_id, Http2Frame { frame_id, payload_size });
    }

    fn associate_tag(&self, frame_id: u32, key: String, value: String) {
        let mut metadata = self.metadata.lock().unwrap();
        let entry = metadata.entry(frame_id).or_insert_with(Vec::new);
        entry.push((key, value));
    }

    fn get_tags(&self, frame_id: u32) -> Option<Vec<(String, String)>> {
        let metadata = self.metadata.lock().unwrap();
        metadata.get(&frame_id).cloned()
    }
}

use std::collections::HashMap;
use std::sync::Mutex;

struct SecretKeyScanner {
    history: Mutex<HashMap<String, Vec<String>>>,
}

impl SecretKeyScanner {
    fn new() -> Self {
        SecretKeyScanner {
            history: Mutex::new(HashMap::new()),
        }
    }

    fn record_leak(&self, key: String, value: String) {
        let mut history = self.history.lock().unwrap();
        history.entry(key).or_insert_with(Vec::new).push(value);
    }

    fn print_all_leaks(&self) -> HashMap<String, Vec<String>> {
        let history = self.history.lock().unwrap().clone();
        history
    }
}

fn main() {
    let scanner = SecretKeyScanner::new();
    scanner.record_leak("API_KEY".to_string(), "abc123xyz".to_string());
    scanner.record_leak("SECRET_SALT".to_string(), "def456uvw".to_string());
    scanner.record_leak("API_KEY".to_string(), "ghi789rst".to_string());

    let leaked_data = scanner.print_all_leaks();

    for (key, values) in leaked_data {
        println!("Found key: {}", key);
        for value in values {
            println!("  - Value found: {}", value);
        }
    }
}

use std::collections::HashMap;

#[derive(Debug, Clone)]
struct CssRule {
    property: String,
    value: String,
}

fn process_properties() -> HashMap<String, Vec<CssRule>> {
    let mut property_map: HashMap<String, Vec<CssRule>> = HashMap::new();

    let rules = vec![
        CssRule { property: "color".to_string(), value: "#ff0000".to_string() },
        CssRule { property: "display".to_string(), value: "inline".to_string() },
        CssRule { property: "background-image".to_string(), value: "url(a.png)".to_string() },
        CssRule { property: "color".to_string(), value: "#0000ff".to_string() },
    ];

    for rule in rules {
        property_map.entry(rule.property.clone()).or_default().push(rule);
    }

    property_map
}
